
.secrets-page {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(350px, 1fr));
  gap: var(--spacing-lg);
}

.card {
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-lg);
  overflow: hidden;

  &.danger-card {
    border-color: rgba(255, 107, 107, 0.3);
  }
  &.success-card {
    border-color: rgba(74, 193, 142, 0.3);
  }
  &.warning-card {
    border-color: rgba(224, 195, 108, 0.3);
  }
}

.card-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: var(--spacing-md) var(--spacing-lg);
  border-bottom: 1px solid var(--color-border);

  h2 {
    display: flex;
    align-items: center;
    gap: var(--spacing-sm);
    font-size: 15px;
    font-weight: 600;
    color: var(--color-text-primary);

    i {
      color: var(--color-gold);
    }
  }

  .danger-card & h2 i {
    color: var(--color-danger);
  }
  .success-card & h2 i {
    color: var(--color-success);
  }
  .warning-card & h2 i {
    color: var(--color-warning);
  }

  .count {
    padding: 2px 8px;
    font-size: 11px;
    font-weight: 600;
    background: var(--color-bg-elevated);
    border-radius: var(--radius-full);
    color: var(--color-text-muted);
  }
}

.card-body {
  padding: var(--spacing-lg);
}

.secret-list {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-md);
}

.secret-item {
  position: relative;
  padding: var(--spacing-md);
  background: var(--color-bg-elevated);
  border-radius: var(--radius-md);
}

.secret-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: var(--spacing-sm);
}

.secret-name {
  font-size: 14px;
  font-weight: 600;
  color: var(--color-text-primary);
}

.risk-tag,
.target-tag,
.type-tag,
.pressure-tag {
  padding: 2px 8px;
  font-size: 10px;
  font-weight: 600;
  border-radius: var(--radius-full);
  background: var(--color-bg-card);
  color: var(--color-text-muted);
}

.risk-tag {
  &.critical {
    background: rgba(255, 107, 107, 0.2);
    color: var(--color-danger);
  }
  &.high {
    background: rgba(224, 195, 108, 0.2);
    color: var(--color-warning);
  }
}

.pressure-tag {
  &.urgent {
    background: rgba(255, 107, 107, 0.2);
    color: var(--color-danger);
  }
  &.high {
    background: rgba(224, 195, 108, 0.2);
    color: var(--color-warning);
  }
}

.secret-content {
  font-size: 13px;
  line-height: 1.5;
  color: var(--color-text-secondary);
  margin-bottom: var(--spacing-sm);

  &.masked:not(.revealed) {
    filter: blur(6px);
    user-select: none;
  }
}

.reveal-btn {
  position: absolute;
  top: var(--spacing-md);
  right: var(--spacing-md);
  width: 28px;
  height: 28px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: var(--color-bg-card);
  border-radius: var(--radius-sm);
  color: var(--color-text-muted);
  font-size: 12px;

  &:hover {
    color: var(--color-text-primary);
  }
}

.secret-meta {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-md);
  font-size: 12px;
  color: var(--color-text-muted);

  .fatal {
    color: var(--color-danger);
  }
  .serious {
    color: var(--color-warning);
  }
}

.trigger {
  margin-top: var(--spacing-sm);
  padding: var(--spacing-sm);
  background: rgba(224, 195, 108, 0.1);
  border-radius: var(--radius-sm);
  font-size: 12px;
  color: var(--color-warning);

  i {
    margin-right: 6px;
  }
}

.empty-hint {
  color: var(--color-text-muted);
  font-style: italic;
  text-align: center;
}
