
.assets-page {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-lg);
}

.overview-cards {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: var(--spacing-md);
}

.overview-card {
  padding: var(--spacing-lg);
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-lg);
  text-align: center;

  .ov-label {
    display: block;
    font-size: 12px;
    color: var(--color-text-muted);
    margin-bottom: var(--spacing-xs);
  }

  .ov-value {
    font-size: 22px;
    font-weight: 700;
    color: var(--color-gold);
    font-family: var(--font-display);
  }

  &.danger {
    border-color: var(--color-danger);

    .ov-value {
      color: var(--color-danger);
    }
  }
}

.assets-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
  gap: var(--spacing-lg);
}

.card {
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-lg);
  overflow: hidden;

  &.danger-card {
    border-color: rgba(255, 107, 107, 0.3);
  }
}

.card-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: var(--spacing-md) var(--spacing-lg);
  border-bottom: 1px solid var(--color-border);

  h2 {
    display: flex;
    align-items: center;
    gap: var(--spacing-sm);
    font-size: 15px;
    font-weight: 600;
    color: var(--color-text-primary);

    i {
      color: var(--color-gold);
    }
  }

  .danger-card & h2 i {
    color: var(--color-danger);
  }

  .count {
    padding: 2px 8px;
    font-size: 11px;
    font-weight: 600;
    background: var(--color-bg-elevated);
    border-radius: var(--radius-full);
    color: var(--color-text-muted);
  }
}

.card-body {
  padding: var(--spacing-lg);
}

.asset-list {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-md);
}

.asset-item {
  padding: var(--spacing-md);
  background: var(--color-bg-elevated);
  border-radius: var(--radius-md);
}

.asset-main {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: var(--spacing-xs);
}

.asset-name {
  font-size: 14px;
  font-weight: 600;
  color: var(--color-text-primary);
}

.asset-value {
  font-size: 14px;
  font-weight: 600;
  color: var(--color-gold);
}

.asset-meta {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-sm);
  font-size: 12px;
  color: var(--color-text-muted);

  .safe {
    color: var(--color-success);
  }
  .ok {
    color: var(--color-info);
  }
  .warn {
    color: var(--color-warning);
  }
  .danger {
    color: var(--color-danger);
  }
}

.empty-hint {
  color: var(--color-text-muted);
  font-style: italic;
  text-align: center;
}
