
.relations-page {
  display: flex;
  flex-direction: column;
  height: 100%;
  gap: var(--spacing-md);
}

// ═══ 工具栏 ═══
.toolbar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  flex-wrap: wrap;
  gap: var(--spacing-md);
}

.filter-group {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-sm);
}

.filter-check {
  display: flex;
  align-items: center;
  cursor: pointer;

  input {
    display: none;
  }

  .check-label {
    padding: 4px 12px;
    font-size: 12px;
    background: var(--color-bg-card);
    border: 1px solid var(--color-border);
    border-radius: var(--radius-full);
    color: var(--color-text-secondary);
    transition: all var(--transition-fast);
  }

  input:checked + .check-label {
    background: var(--filter-color);
    border-color: var(--filter-color);
    color: white;
  }
}

.stats-info {
  display: flex;
  align-items: center;
  gap: var(--spacing-md);
}

.node-count {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 13px;
  color: var(--color-text-secondary);

  i {
    color: var(--color-gold);
  }
}

// ═══ 图例 ═══
.legend {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-md);
  padding: var(--spacing-sm) var(--spacing-md);
  background: var(--color-bg-card);
  border-radius: var(--radius-md);
}

.legend-item {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 11px;
  color: var(--color-text-muted);
}

.legend-line {
  width: 20px;
  height: 3px;
  border-radius: 2px;
}

// ═══ 图形容器 ═══
.graph-container {
  flex: 1;
  position: relative;
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-lg);
  overflow: hidden;
}

.relation-graph {
  width: 100%;
  height: 100%;
  cursor: grab;

  &:active {
    cursor: grabbing;
  }
}

.node {
  cursor: pointer;
  transition: opacity var(--transition-fast);

  &.dimmed {
    opacity: 0.3;
  }

  &.selected circle {
    stroke-width: 3;
    filter: drop-shadow(0 0 8px currentColor);
  }

  &:hover:not(.player) circle {
    filter: brightness(1.2);
  }
}

// ═══ 缩放控制 ═══
.zoom-controls {
  position: absolute;
  bottom: var(--spacing-md);
  right: var(--spacing-md);
  display: flex;
  flex-direction: column;
  gap: 4px;
  background: var(--color-bg-elevated);
  border-radius: var(--radius-md);
  overflow: hidden;

  button {
    width: 32px;
    height: 32px;
    display: flex;
    align-items: center;
    justify-content: center;
    color: var(--color-text-secondary);
    border-bottom: 1px solid var(--color-border);

    &:last-child {
      border-bottom: none;
    }

    &:hover {
      background: var(--color-bg-card);
      color: var(--color-text-primary);
    }
  }
}

// ═══ 侧边面板 ═══
.side-panel {
  position: absolute;
  top: 0;
  right: 0;
  width: 280px;
  height: 100%;
  background: var(--color-bg-card);
  border-left: 1px solid var(--color-border);
  transform: translateX(100%);
  transition: transform var(--transition-slow);

  &.open {
    transform: translateX(0);
  }
}

.panel-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: var(--spacing-md);
  border-bottom: 1px solid var(--color-border);

  h3 {
    font-size: 16px;
    font-weight: 600;
    color: var(--color-text-primary);
  }
}

.close-btn {
  width: 28px;
  height: 28px;
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--color-text-muted);

  &:hover {
    color: var(--color-text-primary);
  }
}

.panel-body {
  padding: var(--spacing-md);
}

.char-meta {
  font-size: 13px;
  color: var(--color-text-secondary);
  margin-bottom: var(--spacing-sm);
}

.char-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 4px;
  margin-bottom: var(--spacing-md);
}

.tag {
  padding: 2px 8px;
  font-size: 10px;
  background: var(--color-bg-elevated);
  border-radius: var(--radius-sm);
  color: var(--color-text-muted);
}

.stat-bars {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-sm);
  margin-bottom: var(--spacing-md);
}

.stat-row {
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
  font-size: 12px;
  color: var(--color-text-muted);

  .bar {
    flex: 1;
    height: 6px;
    background: var(--color-bg-elevated);
    border-radius: 3px;
    overflow: hidden;

    .fill {
      height: 100%;
      background: var(--color-gold);
      border-radius: 3px;
    }
  }
}

.panel-actions {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-sm);
}

.action-link {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: var(--spacing-sm) var(--spacing-md);
  background: var(--color-bg-elevated);
  border-radius: var(--radius-md);
  font-size: 13px;
  color: var(--color-text-secondary);

  &:hover {
    background: var(--color-border);
    color: var(--color-text-primary);
  }

  &.romance {
    background: rgba(255, 77, 109, 0.1);
    color: var(--color-romance-light);

    &:hover {
      background: rgba(255, 77, 109, 0.2);
    }
  }
}
