
.section-accordion {
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-lg);
  overflow: hidden;
  transition: all var(--transition-fast);

  &:hover {
    border-color: var(--color-border-light);
  }
}

// ═══ 头部 ═══
.section-header {
  display: flex;
  align-items: center;
  gap: var(--spacing-md);
  padding: var(--spacing-md) var(--spacing-lg);
  cursor: pointer;
  user-select: none;
  transition: background var(--transition-fast);

  &:hover {
    background: var(--color-bg-elevated);
  }
}

.expand-icon {
  font-size: 12px;
  color: var(--color-text-muted);
  transition: transform var(--transition-fast);

  &.expanded {
    transform: rotate(90deg);
  }
}

.section-title {
  flex: 1;
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
  font-size: 14px;
  font-weight: 600;
  color: var(--color-text-primary);
  margin: 0;

  i {
    color: var(--color-gold);
  }
}

.section-meta {
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
}

.field-count {
  font-size: 12px;
  color: var(--color-text-muted);
  padding: 2px 8px;
  background: var(--color-bg-elevated);
  border-radius: var(--radius-sm);
}

.section-actions {
  display: flex;
  align-items: center;
  gap: var(--spacing-xs);
}

.btn-save {
  display: flex;
  align-items: center;
  gap: 4px;
  padding: 4px 10px;
  background: var(--color-success);
  border-radius: var(--radius-sm);
  font-size: 11px;
  font-weight: 600;
  color: white;
  transition: all var(--transition-fast);

  &:hover:not(:disabled) {
    filter: brightness(1.1);
  }

  &:disabled {
    opacity: 0.5;
    cursor: not-allowed;
  }

  i {
    font-size: 10px;
  }
}

// ═══ 内容区 ═══
.section-body {
  padding: var(--spacing-lg);
  border-top: 1px solid var(--color-border);
}

// ═══ 过渡动画 ═══
.accordion-enter-active,
.accordion-leave-active {
  transition: all 0.2s ease;
  overflow: hidden;
}

.accordion-enter-from,
.accordion-leave-to {
  opacity: 0;
  max-height: 0;
  padding-top: 0;
  padding-bottom: 0;
}

.accordion-enter-to,
.accordion-leave-from {
  opacity: 1;
  max-height: 2000px;
}
