
.profile-page {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-lg);
  max-width: 900px;
  margin: 0 auto;
}

.card {
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-lg);
  overflow: hidden;
}

.card-header {
  padding: var(--spacing-md) var(--spacing-lg);
  border-bottom: 1px solid var(--color-border);

  h2 {
    display: flex;
    align-items: center;
    gap: var(--spacing-sm);
    font-size: 15px;
    font-weight: 600;
    color: var(--color-text-primary);

    i {
      color: var(--color-gold);
    }
  }
}

.card-body {
  padding: var(--spacing-lg);
}

.info-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: var(--spacing-md);

  @media (min-width: 600px) {
    grid-template-columns: repeat(4, 1fr);
  }
}

.info-item {
  display: flex;
  flex-direction: column;
  gap: 4px;

  .label {
    font-size: 11px;
    color: var(--color-text-muted);
    text-transform: uppercase;
    letter-spacing: 0.5px;
  }

  .value {
    font-size: 14px;
    color: var(--color-text-secondary);

    &.gold {
      color: var(--color-gold);
      font-weight: 600;
    }
  }
}

.position-main {
  display: flex;
  flex-direction: column;
  gap: 4px;
  margin-bottom: var(--spacing-lg);
  padding-bottom: var(--spacing-lg);
  border-bottom: 1px solid var(--color-border);

  .position-title {
    font-size: 18px;
    font-weight: 700;
    color: var(--color-text-primary);
  }

  .position-unit {
    font-size: 14px;
    color: var(--color-text-secondary);
  }
}

.ability-list {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-md);
}

.ability-item {
  display: flex;
  align-items: center;
  gap: var(--spacing-md);

  .ability-name {
    width: 80px;
    font-size: 13px;
    color: var(--color-text-secondary);
  }

  .ability-bar {
    flex: 1;
    height: 10px;
    background: var(--color-bg-elevated);
    border-radius: 5px;
    overflow: hidden;
  }

  .ability-fill {
    height: 100%;
    border-radius: 5px;
    transition: width 0.3s;

    &.t0 {
      background: linear-gradient(90deg, #ffd700, #ffec8b);
    }
    &.t1 {
      background: linear-gradient(90deg, var(--color-success), #6dd5a0);
    }
    &.t2 {
      background: linear-gradient(90deg, var(--color-info), #a3c4f7);
    }
    &.t3 {
      background: linear-gradient(90deg, var(--color-warning), #f0d78c);
    }
    &.t4 {
      background: linear-gradient(90deg, var(--color-danger), #ff9999);
    }
  }

  .ability-value {
    width: 30px;
    text-align: right;
    font-size: 14px;
    font-weight: 600;
    color: var(--color-text-primary);
  }
}

.timeline {
  position: relative;
  padding-left: 20px;

  &::before {
    content: '';
    position: absolute;
    left: 6px;
    top: 0;
    bottom: 0;
    width: 2px;
    background: var(--color-border);
  }
}

.timeline-item {
  position: relative;
  padding-bottom: var(--spacing-lg);

  &:last-child {
    padding-bottom: 0;
  }
}

.timeline-dot {
  position: absolute;
  left: -17px;
  top: 4px;
  width: 10px;
  height: 10px;
  background: var(--color-gold);
  border-radius: 50%;
}

.timeline-content {
  padding-left: var(--spacing-md);
}

.timeline-header {
  display: flex;
  justify-content: space-between;
  align-items: baseline;
  margin-bottom: 4px;
}

.timeline-title {
  font-size: 14px;
  font-weight: 600;
  color: var(--color-text-primary);
}

.timeline-period {
  font-size: 12px;
  color: var(--color-text-muted);
}

.timeline-meta {
  display: flex;
  gap: var(--spacing-md);
  font-size: 12px;
  color: var(--color-text-secondary);
  margin-bottom: var(--spacing-xs);
}

.timeline-desc {
  font-size: 13px;
  color: var(--color-text-muted);
  line-height: 1.5;
}
