
.record-table {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-md);
}

// ═══ 工具栏 ═══
.table-toolbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--spacing-md);
  flex-wrap: wrap;
}

.search-box {
  flex: 1;
  min-width: 150px;
  max-width: 250px;
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
  padding: var(--spacing-xs) var(--spacing-sm);
  background: var(--color-bg-elevated);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);

  i {
    color: var(--color-text-muted);
    font-size: 12px;
  }

  input {
    flex: 1;
    background: transparent;
    color: var(--color-text-primary);
    font-size: 12px;

    &::placeholder {
      color: var(--color-text-muted);
    }
  }
}

.btn-add {
  display: flex;
  align-items: center;
  gap: 4px;
  padding: var(--spacing-xs) var(--spacing-md);
  background: var(--color-gold);
  border-radius: var(--radius-md);
  font-size: 12px;
  font-weight: 600;
  color: var(--color-bg-dark);

  &:hover {
    filter: brightness(1.1);
  }
}

// ═══ 记录列表 ═══
.record-list {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-sm);
}

.record-item {
  background: var(--color-bg-elevated);
  border-radius: var(--radius-md);
  overflow: hidden;
  transition: all var(--transition-fast);

  &.expanded {
    background: var(--color-bg-card);
    box-shadow: var(--shadow-sm);
  }
}

.record-header {
  display: flex;
  align-items: center;
  gap: var(--spacing-md);
  padding: var(--spacing-sm) var(--spacing-md);
  cursor: pointer;

  &:hover {
    background: var(--color-bg-card);
  }

  .expand-icon {
    font-size: 10px;
    color: var(--color-text-muted);
    transition: transform var(--transition-fast);

    &.expanded {
      transform: rotate(90deg);
    }
  }
}

.record-info {
  flex: 1;
  min-width: 0;
  display: flex;
  align-items: baseline;
  gap: var(--spacing-sm);

  .record-name {
    font-size: 13px;
    font-weight: 600;
    color: var(--color-text-primary);
  }

  .record-meta {
    font-size: 11px;
    color: var(--color-text-muted);
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }
}

.record-actions {
  display: flex;
  gap: var(--spacing-xs);
}

.btn-delete {
  width: 24px;
  height: 24px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: var(--radius-sm);
  font-size: 11px;
  color: var(--color-text-muted);

  &:hover {
    background: rgba(255, 107, 107, 0.1);
    color: var(--color-danger);
  }
}

// ═══ 记录内容 ═══
.record-body {
  padding: var(--spacing-md);
  border-top: 1px solid var(--color-border);
}

.field-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: var(--spacing-sm) var(--spacing-md);

  @media (max-width: 500px) {
    grid-template-columns: 1fr;
  }
}

.field-row {
  display: flex;
  flex-direction: column;
  gap: 2px;

  &.full {
    grid-column: 1 / -1;
  }

  label {
    font-size: 10px;
    color: var(--color-text-muted);
    text-transform: uppercase;
    letter-spacing: 0.5px;
  }

  input[type='text'],
  input[type='number'],
  textarea {
    padding: var(--spacing-xs) var(--spacing-sm);
    background: var(--color-bg-elevated);
    border: 1px solid var(--color-border);
    border-radius: var(--radius-sm);
    color: var(--color-text-primary);
    font-size: 12px;

    &:focus {
      border-color: var(--color-gold);
      outline: none;
    }
  }

  textarea {
    resize: vertical;
    min-height: 50px;
  }
}

.checkbox-wrapper {
  display: flex;
  align-items: center;
  gap: var(--spacing-xs);
  font-size: 12px;
  color: var(--color-text-secondary);
  cursor: pointer;

  input[type='checkbox'] {
    accent-color: var(--color-gold);
  }
}

.array-value {
  display: flex;
  flex-wrap: wrap;
  gap: 4px;
  padding: var(--spacing-xs);
  background: var(--color-bg-elevated);
  border-radius: var(--radius-sm);
  min-height: 28px;
}

.array-item {
  padding: 2px 6px;
  background: var(--color-bg-card);
  border-radius: var(--radius-sm);
  font-size: 11px;
  color: var(--color-text-secondary);
}

.object-value {
  padding: var(--spacing-xs) var(--spacing-sm);
  background: var(--color-bg-elevated);
  border-radius: var(--radius-sm);
  font-size: 10px;
  font-family: var(--font-mono);
  color: var(--color-text-muted);
  overflow-x: auto;
  max-height: 100px;
}

// ═══ 空状态 ═══
.empty-state {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: var(--spacing-sm);
  padding: var(--spacing-xl);
  color: var(--color-text-muted);

  i {
    font-size: 32px;
  }

  p {
    font-size: 13px;
  }
}

// ═══ 分页 ═══
.pagination {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: var(--spacing-md);

  button {
    width: 28px;
    height: 28px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: var(--color-bg-elevated);
    border: 1px solid var(--color-border);
    border-radius: var(--radius-sm);
    font-size: 11px;
    color: var(--color-text-secondary);

    &:hover:not(:disabled) {
      background: var(--color-bg-card);
      color: var(--color-text-primary);
    }

    &:disabled {
      opacity: 0.4;
      cursor: not-allowed;
    }
  }

  .page-info {
    font-size: 12px;
    color: var(--color-text-muted);
  }
}

// ═══ 过渡动画 ═══
.record-enter-active,
.record-leave-active {
  transition: all 0.2s ease;
}

.record-enter-from,
.record-leave-to {
  opacity: 0;
  transform: translateX(-10px);
}

.record-move {
  transition: transform 0.2s ease;
}

.expand-enter-active,
.expand-leave-active {
  transition: all 0.2s ease;
  overflow: hidden;
}

.expand-enter-from,
.expand-leave-to {
  opacity: 0;
  max-height: 0;
  padding-top: 0;
  padding-bottom: 0;
}

.expand-enter-to,
.expand-leave-from {
  opacity: 1;
  max-height: 1000px;
}
