
.variables-page {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-lg);
}

// ═══ 工具栏 ═══
.toolbar {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-md);
  align-items: center;
  justify-content: space-between;
}

.search-box {
  flex: 1;
  min-width: 200px;
  max-width: 300px;
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
  padding: var(--spacing-sm) var(--spacing-md);
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);

  i {
    color: var(--color-text-muted);
  }

  input {
    flex: 1;
    color: var(--color-text-primary);

    &::placeholder {
      color: var(--color-text-muted);
    }
  }
}

.toolbar-actions {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-sm);
  align-items: center;
}

.toggle-filled {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 13px;
  color: var(--color-text-secondary);
  cursor: pointer;

  input {
    accent-color: var(--color-gold);
  }
}

.action-btn {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: var(--spacing-sm) var(--spacing-md);
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
  font-size: 12px;
  color: var(--color-text-secondary);

  &:hover {
    background: var(--color-bg-elevated);
    color: var(--color-text-primary);
  }
}

.save-btn {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: var(--spacing-sm) var(--spacing-md);
  background: var(--color-gold);
  border-radius: var(--radius-md);
  font-size: 13px;
  font-weight: 600;
  color: var(--color-bg-dark);

  &:disabled {
    opacity: 0.5;
    cursor: not-allowed;
  }

  &:hover:not(:disabled) {
    filter: brightness(1.1);
  }
}

// ═══ 分区列表 ═══
.sections-list {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-md);
}

// ═══ 字段组 ═══
.field-group {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: var(--spacing-md);

  @media (max-width: 600px) {
    grid-template-columns: 1fr;
  }
}

.field-row {
  display: flex;
  flex-direction: column;
  gap: 4px;

  &.full {
    grid-column: 1 / -1;
  }

  label {
    font-size: 11px;
    color: var(--color-text-muted);
    text-transform: uppercase;
    letter-spacing: 0.5px;
  }

  input[type='text'],
  input[type='number'],
  textarea,
  select {
    padding: var(--spacing-sm) var(--spacing-md);
    background: var(--color-bg-elevated);
    border: 1px solid var(--color-border);
    border-radius: var(--radius-md);
    color: var(--color-text-primary);
    font-size: 13px;

    &:focus {
      border-color: var(--color-gold);
      outline: none;
    }
  }

  textarea {
    resize: vertical;
    min-height: 60px;
  }

  .computed-value {
    padding: var(--spacing-sm) var(--spacing-md);
    background: var(--color-bg-elevated);
    border-radius: var(--radius-md);
    font-size: 13px;
    color: var(--color-gold);
  }
}

// ═══ 子区块 ═══
.sub-section {
  margin-top: var(--spacing-lg);
  padding-top: var(--spacing-lg);
  border-top: 1px solid var(--color-border);

  &:first-child {
    margin-top: 0;
    padding-top: 0;
    border-top: none;
  }

  h5 {
    display: flex;
    align-items: center;
    gap: var(--spacing-sm);
    font-size: 12px;
    font-weight: 600;
    color: var(--color-text-secondary);
    margin: 0 0 var(--spacing-md);

    i {
      color: var(--color-gold);
    }
  }
}

// ═══ 数值网格 ═══
.stats-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: var(--spacing-md) var(--spacing-lg);

  @media (max-width: 600px) {
    grid-template-columns: 1fr;
  }
}

// ═══ 字段计数 ═══
.field-count {
  font-size: 12px;
  color: var(--color-text-muted);
  padding: 2px 8px;
  background: var(--color-bg-elevated);
  border-radius: var(--radius-sm);

  &.romance {
    background: rgba(255, 77, 109, 0.15);
    color: var(--color-romance-light);
  }
}

// ═══ 导入弹窗 ═══
.import-content {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-md);
}

.import-hint {
  font-size: 13px;
  color: var(--color-text-secondary);
  text-align: center;
}

.import-dropzone {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: var(--spacing-sm);
  padding: var(--spacing-xl);
  background: var(--color-bg-elevated);
  border: 2px dashed var(--color-border);
  border-radius: var(--radius-lg);
  transition: all var(--transition-fast);

  &.dragover {
    border-color: var(--color-gold);
    background: rgba(216, 166, 87, 0.1);
  }

  i {
    font-size: 32px;
    color: var(--color-text-muted);
  }

  p {
    font-size: 13px;
    color: var(--color-text-muted);
  }

  .upload-btn {
    padding: var(--spacing-sm) var(--spacing-lg);
    background: var(--color-gold);
    border-radius: var(--radius-md);
    font-size: 13px;
    font-weight: 600;
    color: var(--color-bg-dark);
    cursor: pointer;

    &:hover {
      filter: brightness(1.1);
    }
  }
}

.import-preview {
  h5 {
    font-size: 12px;
    color: var(--color-text-muted);
    margin-bottom: var(--spacing-xs);
  }

  pre {
    padding: var(--spacing-sm);
    background: var(--color-bg-elevated);
    border-radius: var(--radius-md);
    font-size: 10px;
    font-family: var(--font-mono);
    color: var(--color-text-muted);
    max-height: 150px;
    overflow: auto;
  }
}

// ═══ 按钮样式 ═══
.btn-secondary {
  padding: var(--spacing-sm) var(--spacing-lg);
  background: transparent;
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
  font-size: 13px;
  color: var(--color-text-secondary);

  &:hover {
    background: var(--color-bg-elevated);
    color: var(--color-text-primary);
  }
}

.btn-primary {
  display: flex;
  align-items: center;
  gap: var(--spacing-xs);
  padding: var(--spacing-sm) var(--spacing-lg);
  background: var(--color-gold);
  border-radius: var(--radius-md);
  font-size: 13px;
  font-weight: 600;
  color: var(--color-bg-dark);

  &:hover:not(:disabled) {
    filter: brightness(1.1);
  }

  &:disabled {
    opacity: 0.6;
    cursor: not-allowed;
  }
}
