
.opportunities-page {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-lg);
}

.card {
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-lg);
  overflow: hidden;

  &.success-card {
    border-color: rgba(74, 193, 142, 0.3);
  }
  &.danger-card {
    border-color: rgba(255, 107, 107, 0.3);
  }
}

.card-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: var(--spacing-md) var(--spacing-lg);
  border-bottom: 1px solid var(--color-border);

  h2 {
    display: flex;
    align-items: center;
    gap: var(--spacing-sm);
    font-size: 15px;
    font-weight: 600;
    color: var(--color-text-primary);

    i {
      color: var(--color-gold);
    }
  }

  .success-card & h2 i {
    color: var(--color-success);
  }
  .danger-card & h2 i {
    color: var(--color-danger);
  }

  .count {
    padding: 2px 8px;
    font-size: 11px;
    font-weight: 600;
    background: var(--color-bg-elevated);
    border-radius: var(--radius-full);
    color: var(--color-text-muted);
  }
}

.card-body {
  padding: var(--spacing-lg);
}

.item-list {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-md);
}

.item-card {
  padding: var(--spacing-md);
  background: var(--color-bg-elevated);
  border-radius: var(--radius-md);
  border-left: 3px solid var(--color-border);

  &.success {
    border-left-color: var(--color-success);
  }
  &.danger {
    border-left-color: var(--color-danger);
  }
}

.item-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: var(--spacing-sm);
}

.item-name {
  font-size: 15px;
  font-weight: 600;
  color: var(--color-text-primary);
}

.level-tag {
  padding: 2px 8px;
  font-size: 10px;
  font-weight: 600;
  border-radius: var(--radius-full);
  background: var(--color-bg-card);
  color: var(--color-text-muted);

  &.legendary {
    background: linear-gradient(90deg, #ffd700, #ffec8b);
    color: var(--color-bg-dark);
  }
  &.epic {
    background: rgba(74, 193, 142, 0.2);
    color: var(--color-success);
  }
  &.fatal {
    background: rgba(255, 107, 107, 0.2);
    color: var(--color-danger);
  }
  &.severe {
    background: rgba(224, 195, 108, 0.2);
    color: var(--color-warning);
  }
}

.item-content {
  font-size: 13px;
  line-height: 1.5;
  color: var(--color-text-secondary);
  margin-bottom: var(--spacing-sm);
}

.item-meta {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-md);
  font-size: 12px;
  color: var(--color-text-muted);
  margin-bottom: var(--spacing-xs);

  i {
    margin-right: 4px;
  }

  .high-prob {
    color: var(--color-danger);
  }
  .mid-prob {
    color: var(--color-warning);
  }
}

.item-detail {
  font-size: 12px;
  color: var(--color-text-secondary);
  padding: var(--spacing-xs) 0;

  strong {
    color: var(--color-text-muted);
  }

  &.warning {
    color: var(--color-warning);
  }
}

.todo-list {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-sm);
}

.todo-item {
  padding: var(--spacing-md);
  background: var(--color-bg-elevated);
  border-radius: var(--radius-md);
  border-left: 3px solid var(--color-border);

  &.urgent {
    border-left-color: var(--color-danger);
  }
  &.high {
    border-left-color: var(--color-warning);
  }
  &.normal {
    border-left-color: var(--color-info);
  }
}

.todo-main {
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
  margin-bottom: var(--spacing-xs);
}

.urgency-tag {
  padding: 2px 6px;
  font-size: 10px;
  font-weight: 600;
  background: var(--color-bg-card);
  border-radius: var(--radius-sm);
  color: var(--color-text-muted);

  .urgent & {
    color: var(--color-danger);
  }
  .high & {
    color: var(--color-warning);
  }
}

.todo-text {
  font-size: 13px;
  color: var(--color-text-primary);
}

.todo-meta {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-md);
  font-size: 12px;
  color: var(--color-text-muted);
}

.deadline {
  i {
    margin-right: 4px;
  }
}

.related-chars {
  display: flex;
  gap: var(--spacing-xs);
}

.char-link {
  padding: 2px 8px;
  background: var(--color-bg-card);
  border-radius: var(--radius-sm);
  font-size: 11px;
  color: var(--color-text-secondary);

  &:hover {
    background: var(--color-border);
    color: var(--color-text-primary);
  }
}

.empty-hint {
  color: var(--color-text-muted);
  font-style: italic;
  text-align: center;
}
